import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:geolocator/geolocator.dart';
import 'package:flutter_map/flutter_map.dart';
import 'package:latlong2/latlong.dart';
const apiBase=String.fromEnvironment('API_BASE_URL', defaultValue:'http://127.0.0.1:8003');
const green=Color(0xFF2F8F46);const dark=Color(0xFF0D5B2A);void main()=>runApp(const App());
class App extends StatefulWidget{const App({super.key});@override State<App> createState()=>_AppState();}class _AppState extends State<App>{String? token;Map? user;@override Widget build(BuildContext c)=>MaterialApp(debugShowCheckedModeBanner:false,theme:ThemeData(colorScheme:ColorScheme.fromSeed(seedColor:green),useMaterial3:true),home:token==null?Login(onLogin:(t,u)=>setState((){token=t;user=u;})):Home(token:token!,user:user??{},logout:()=>setState(()=>token=null)));}
class Api{Api(this.t);final String t;Map<String,String> get h=>{'Content-Type':'application/json','Authorization':'Bearer $t'};Future<dynamic> get(String p)async{final r=await http.get(Uri.parse('$apiBase$p'),headers:h);if(r.statusCode>=400)throw Exception(r.body);return jsonDecode(r.body);}Future<dynamic> post(String p,Map b)async{final r=await http.post(Uri.parse('$apiBase$p'),headers:h,body:jsonEncode(b));if(r.statusCode>=400)throw Exception(r.body);return jsonDecode(r.body);} }
class Login extends StatefulWidget{const Login({super.key,required this.onLogin});final void Function(String,Map) onLogin;@override State<Login> createState()=>_LoginState();}class _LoginState extends State<Login>{final u=TextEditingController(text:'0001');final p=TextEditingController(text:'1234');String error='';bool loading=false;Future<void> submit()async{setState(()=>loading=true);try{final r=await http.post(Uri.parse('$apiBase/auth/login'),headers:{'Content-Type':'application/json'},body:jsonEncode({'username':u.text,'codigo_empleado':u.text,'password':p.text}));if(r.statusCode>=400)throw Exception(r.body);final d=jsonDecode(r.body);widget.onLogin(d['access_token'],d['user']??{});}catch(e){setState(()=>error='No se pudo iniciar sesión.');}finally{if(mounted)setState(()=>loading=false);}}@override Widget build(BuildContext c)=>Scaffold(body:Container(decoration:const BoxDecoration(gradient:LinearGradient(colors:[green,dark])),child:Center(child:SingleChildScrollView(padding:const EdgeInsets.all(22),child:Card(shape:RoundedRectangleBorder(borderRadius:BorderRadius.circular(26)),child:Padding(padding:const EdgeInsets.all(24),child:Column(mainAxisSize:MainAxisSize.min,crossAxisAlignment:CrossAxisAlignment.stretch,children:[Image.asset('assets/logo_proempresa.png'),const SizedBox(height:20),const Text('Fuerza de Ventas',style:TextStyle(fontWeight:FontWeight.w900,fontSize:28)),TextField(controller:u,decoration:const InputDecoration(labelText:'Usuario / código')),TextField(controller:p,obscureText:true,decoration:const InputDecoration(labelText:'Clave')),if(error.isNotEmpty)Text(error,style:const TextStyle(color:Colors.red,fontWeight:FontWeight.bold)),const SizedBox(height:18),FilledButton(onPressed:loading?null:submit,child:Text(loading?'Ingresando...':'Ingresar'))]))))));}
class Home extends StatefulWidget{const Home({super.key,required this.token,required this.user,required this.logout});final String token;final Map user;final VoidCallback logout;@override State<Home> createState()=>_HomeState();}class _HomeState extends State<Home>{int tab=0;late Api api=Api(widget.token);@override Widget build(BuildContext c){final pages=[Cartera(api:api),Solicitudes(api:api),Perfil(user:widget.user,logout:widget.logout)];return Scaffold(appBar:AppBar(title:const Text('ProEmpresa Campo'),backgroundColor:green,foregroundColor:Colors.white),body:pages[tab],bottomNavigationBar:NavigationBar(selectedIndex:tab,onDestinationSelected:(i)=>setState(()=>tab=i),destinations:const[NavigationDestination(icon:Icon(Icons.business_center),label:'Cartera'),NavigationDestination(icon:Icon(Icons.request_page),label:'Solicitudes'),NavigationDestination(icon:Icon(Icons.person),label:'Más')]),);}}
class Cartera extends StatefulWidget{const Cartera({super.key,required this.api});final Api api;@override State<Cartera> createState()=>_CarteraState();}class _CarteraState extends State<Cartera>{late Future<List> data;@override void initState(){super.initState();data=widget.api.get('/cartera').then((v)=>v as List);}@override Widget build(BuildContext c)=>FutureBuilder<List>(future:data,builder:(c,s){if(!s.hasData)return const Center(child:CircularProgressIndicator());return RefreshIndicator(onRefresh:()async{setState(()=>data=widget.api.get('/cartera').then((v)=>v as List));},child:ListView(padding:const EdgeInsets.all(16),children:[Image.asset('assets/logo_proempresa.png'),const SizedBox(height:12),const Text('Cartera comercial',style:TextStyle(fontWeight:FontWeight.w900,fontSize:24)),...s.data!.map((x)=>Card(child:ListTile(leading:const Icon(Icons.store,color:green),title:Text('${x['nombres']} ${x['apellidos']}'),subtitle:Text('${x['numero_expediente']??'Sin solicitud'} · ${x['nombre_negocio']??''}\n${x['direccion_negocio']??''}'),isThreeLine:true,trailing:Chip(label:Text(x['estado_visita']??'')),onTap:()=>Navigator.push(c,MaterialPageRoute(builder:(_)=>Detalle(api:widget.api,item:x))).then((_)=>setState(()=>data=widget.api.get('/cartera').then((v)=>v as List))))))]));});}
class Detalle extends StatefulWidget{const Detalle({super.key,required this.api,required this.item});final Api api;final Map item;@override State<Detalle> createState()=>_DetalleState();}class _DetalleState extends State<Detalle>{final obs=TextEditingController(text:'Cliente interesado. Se realizó entrevista inicial.');String msg='';Future<Position?> gps()async{var perm=await Geolocator.checkPermission();if(perm==LocationPermission.denied)perm=await Geolocator.requestPermission();if(perm==LocationPermission.denied||perm==LocationPermission.deniedForever)return null;return Geolocator.getCurrentPosition(desiredAccuracy:LocationAccuracy.high);}Future<void> visita()async{try{final p=await gps();final r=await widget.api.post('/cartera/${widget.item['id']}/visita',{'resultado':'cliente_interesado','observacion':obs.text,'lat':p?.latitude,'lng':p?.longitude,'precision_gps':p?.accuracy});setState(()=>msg='Visita registrada: ${r['estado']}');}catch(e){setState(()=>msg='No se pudo registrar visita.');}}@override Widget build(BuildContext c){final lat=double.tryParse('${widget.item['lat_negocio']??-12.0654}')??-12.0654;final lng=double.tryParse('${widget.item['lng_negocio']??-75.2046}')??-75.2046;return Scaffold(appBar:AppBar(title:const Text('Ficha del cliente')),body:ListView(padding:const EdgeInsets.all(16),children:[Text('${widget.item['nombres']} ${widget.item['apellidos']}',style:const TextStyle(fontWeight:FontWeight.w900,fontSize:24)),Text(widget.item['numero_documento']??''),const SizedBox(height:12),Card(child:ListTile(title:Text(widget.item['nombre_negocio']??'Negocio'),subtitle:Text(widget.item['direccion_negocio']??''))),SizedBox(height:260,child:FlutterMap(options:MapOptions(initialCenter:LatLng(lat,lng),initialZoom:16),children:[TileLayer(urlTemplate:'https://tile.openstreetmap.org/{z}/{x}/{y}.png',userAgentPackageName:'proempresa.fuerzaventas'),MarkerLayer(markers:[Marker(point:LatLng(lat,lng),child:const Icon(Icons.location_pin,color:Colors.red,size:42))])])),const SizedBox(height:12),TextField(controller:obs,maxLines:3,decoration:const InputDecoration(labelText:'Resultado de visita')),const SizedBox(height:12),FilledButton.icon(onPressed:visita,icon:const Icon(Icons.gps_fixed),label:const Text('Registrar visita con GPS')),if(msg.isNotEmpty)Card(child:Padding(padding:const EdgeInsets.all(14),child:Text(msg,style:const TextStyle(fontWeight:FontWeight.bold))))]));}}
class Solicitudes extends StatefulWidget{const Solicitudes({super.key,required this.api});final Api api;@override State<Solicitudes> createState()=>_SolicitudesState();}class _SolicitudesState extends State<Solicitudes>{late Future<List> data;@override void initState(){super.initState();data=widget.api.get('/solicitudes').then((v)=>v as List);}@override Widget build(BuildContext c)=>FutureBuilder<List>(future:data,builder:(c,s){if(!s.hasData)return const Center(child:CircularProgressIndicator());return ListView(padding:const EdgeInsets.all(16),children:[const Text('Solicitudes asignadas',style:TextStyle(fontSize:24,fontWeight:FontWeight.w900)),...s.data!.map((x)=>Card(child:ListTile(title:Text(x['numero_expediente']??''),subtitle:Text('${x['nombres']} ${x['apellidos']} · S/ ${x['monto_solicitado']}'),trailing:Chip(label:Text(x['estado']??'')))))]);});}
class Perfil extends StatelessWidget{const Perfil({super.key,required this.user,required this.logout});final Map user;final VoidCallback logout;@override Widget build(BuildContext c)=>ListView(padding:const EdgeInsets.all(16),children:[Image.asset('assets/logo_proempresa.png'),ListTile(title:Text(user['nombre']??'Asesor'),subtitle:Text(user['codigo_empleado']??'')),FilledButton.tonal(onPressed:logout,child:const Text('Cerrar sesión'))]);}
